class Solution {
    public int search(int[] nums, int target) {
        int lo = 0, hi = nums.length - 1;

        while (lo <= hi) {
            int mid = lo + (hi - lo) / 2;

            if (nums[mid] == target) {
                return mid;
            } else if (nums[mid] < target) {
                lo = mid + 1;   // target is to the RIGHT
            } else {
                hi = mid - 1;   // target is to the LEFT
            }
        }

        return -1;  // not found
    }
}
// Time: O(log n) | Space: O(1)
